// Sensing components
instance TemperatureSensor : DTDFVocab:SensingComponent [
    base:desc "A temperature sensor defined in the enriched BIM with measurement unit °C and physical location in the main corridor."
    DTDFVocab:producedData TempTelemetryTransmitted
]

instance HumiditySensor : DTDFVocab:SensingComponent [
    base:desc "A humidity sensor specified in BIM metadata with unit %RH and located in the HVAC return air duct."
    DTDFVocab:producedData HumidityTelemetryTransmitted
]

instance EnergyConsumptionSensor : DTDFVocab:SensingComponent [
    base:desc "An energy consumption sensor embedded in the building's electrical substation, reporting kWh usage."
    DTDFVocab:producedData EnergyTelemetryTransmitted
]

// Data transmitted
instance TempTelemetryTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TemperatureSensor
]

instance HumidityTelemetryTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HumiditySensor
]

instance EnergyTelemetryTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom EnergyConsumptionSensor
]

// Data derived from transmitted payloads
instance TempData : DTDFVocab:Data [
    base:desc "Temperature telemetry data validated against policy rules (acceptable range 5‑35 °C) and stored in Ditto."
    DTDFVocab:fromData TempTelemetryTransmitted
    DTDFVocab:inputTo DittoDataStoreEnabler
]

instance HumidityData : DTDFVocab:Data [
    base:desc "Humidity data validated against units (%RH) and bounded by policy (20‑80 %) before storage."
    DTDFVocab:fromData HumidityTelemetryTransmitted
    DTDFVocab:inputTo DittoDataStoreEnabler
]

instance EnergyData : DTDFVocab:Data [
    base:desc "Energy consumption data received via Hono MQTT broker and persisted in Ditto's event store."
    DTDFVocab:fromData EnergyTelemetryTransmitted
    DTDFVocab:inputTo DittoDataStoreEnabler
]

// Enablers that connect data to services
instance DittoDataStoreEnabler : DTDFVocab:Enabler [
    base:desc "Enabler that forwards validated data to Ditto and allows query via REST endpoints."
    DTDFVocab:enables MonitoringService, PredictiveAnalyticsService
]

instance DittoBrokersEnabler : DTDFVocab:Enabler [
    base:desc "Enabler that routes real‑time events through Eclipse Hono MQTT broker with at‑least‑once delivery."
    DTDFVocab:enables MonitoringService
]

instance DittoControllerEnabler : DTDFVocab:Enabler [
    base:desc "Ensures command messages to actuators are sent via DittoController, subject to policy validation."
    DTDFVocab:enables ControlService
]

// Services
instance MonitoringService : DTDFVocab:Service [
    base:desc "Service that aggregates live sensor streams and provides status dashboards to Facility Managers."
    DTDFVocab:provides TemperatureInsight, HumidityInsight, EnergyEfficiencyInsight
