instance VisualizationService : DTDFVocab:Service [
    base:desc "Service delivering immersive visualizations of structural and operational metrics in Unreal Engine."
    DTDFVocab:provides TemperatureInsight, HumidityInsight, EnergyEfficiencyInsight
]

instance PredictiveAnalyticsService : DTDFVocab:Service [
    base:desc "Predictive analytics service generating alerts and optimization suggestions for HVAC and lighting."
    DTDFVocab:provides HVACOptimizationInsight, LightingControlInsight
